request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orig ?norm WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model tai:normalizedId ?norm . }
  FILTER(STR(?orig) = "2d225c9ff86b443c9f6bc6cfe687afbc" || STR(?norm) = "2d225c9ff86b443c9f6bc6cfe687afbc")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?start ?startName ?sink ?sinkName ?sinkType WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  # Reach any node reachable from a StartEvent via outgoing sequence flows.
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?sink .
  FILTER EXISTS { ?sink a ?sinkType }
  OPTIONAL { ?sink bbo:name ?sinkName . }

  # Keep only sinks that are NOT EndEvents.
  FILTER NOT EXISTS { ?sink a bboExt:EndEvent }
}
LIMIT 25
